from typing import List

def coin_change(coins: List[int], amount: int) -> int:
    # Check for valid inputs
    if not coins or amount < 0:
        return -1

    # Initialize a cache for memoization
    cache = {}

    def dp(remaining):
        # Base case: if remaining amount is 0, no more coins are needed
        if remaining == 0:
            return 0
        # If the result is already computed, return it from cache
        if remaining in cache:
            return cache[remaining]

        min_coins = float('inf')
        for coin in coins:
            if remaining - coin >= 0:
                res = dp(remaining - coin)
                if res != -1:  # Only consider valid results
                    min_coins = min(min_coins, res + 1)

