def max_segments(n, a, b, c):
    if n < 0 or a < 0 or b < 0 or c < 0:
        return "Error: All inputs must be non-negative integers."

    total_segments = 0
    remaining_length = n

    while remaining_length >= min(a, b, c):
        if remaining_length >= a:
            remaining_length -= a
            total_segments += 1
        elif remaining_length >= b:
            remaining_length -= b
            total_segments += 1
        elif remaining_length >= c:
            remaining_length -= c
            total_segments += 1

    return total_segments

assert max_segments(7, 5, 2, 5) == 2
assert max_segments(17, 2, 1, 3) == 8
assert max_segments(18, 16, 3, 6) == 6

